#include <iostream>#include <string>using namespace std;int main() {string nomeJogador;int escolha;bool continuar = true;    cout << "=== JOGO DO GATO E DO RATO 🐱🐭 ===" << endl;    cout << "Digite o teu nome: ";    cin >> nomeJogador;    while (continuar) {        cout << endl;        cout << "Olá, " << nomeJogador << "! Escolhe uma acao:" << endl;        cout << "1 - Correr atras do rato" << endl;        cout << "2 - Comer queijo" << endl;        cout << "3 - Dormir" << endl;        cout << "0 - Sair do jogo" << endl;        cout << "Opcao: ";        cin >> escolha;        cout << endl;        if (escolha == 1) {            cout << "Voce correu atras do rato! 🏃" << endl;            // Loop for (repetição)            for (int i = 1; i <= 3; i++) {                cout << "Correndo... passo " << i << endl;            }            cout << "O rato escapou! 😆" << endl;        }        else if (escolha == 2) {            cout << "Voce decidiu comer queijo 🧀" << endl;        }        else if (escolha == 3) {            cout << "Voce foi dormir 😴" << endl;        }        else if (escolha == 0) {            cout << "Saindo do jogo... ate logo! 👋" << endl;            continuar = false;        }        else {            cout << "Opcao invalida 😅" << endl;        }    }    return 0;}